// Live Update техлогия

import React, { useState, useEffect, useContext, useRef } from 'react';
import { ToolsContext } from '../../../../ToolsContext';
import { CiCirclePlus } from "react-icons/ci";
import './full_screeen_mode.css';

const FullscreenMode = () => {
    const { fullscreenPosts, slideInterval, setFullscreenMode, setFullscreenPosts } = useContext(ToolsContext);
    const [currentImageIndex, setCurrentImageIndex] = useState(0);
    const [showIntervalInput, setShowIntervalInput] = useState(false);
    const [allPostsWithFiles, setAllPostsWithFiles] = useState([]);

    const inactivityTimeoutRef = useRef(null);
    const SEVEN_MINUTES = 420000; // 7 минут в миллисекундах

    // Check if there are any posts with images
    const hasImages = fullscreenPosts.some(post => post.file);

    // Use different group size based on whether there are images
    const groupSize = hasImages ? 8 : 15;
    const currentGroupStart = Math.floor((fullscreenPosts.length - 1) / groupSize) * groupSize;
    const postsToShow = fullscreenPosts.slice(currentGroupStart);

    useEffect(() => {
        // Add new posts with files to our persistent collection
        setAllPostsWithFiles(prev => {
            const newPostsWithFiles = fullscreenPosts.filter(post =>
                post.file && !prev.some(existing => existing.id === post.id)
            );
            return [...prev, ...newPostsWithFiles];
        });
    }, [fullscreenPosts]);

    // Use all accumulated posts with files (images and videos persist), flatten files arrays
    const allMediaToShow = allPostsWithFiles.flatMap(post =>
        Array.isArray(post.file) ? post.file : [post.file]
    ).filter(file => file && file.type && (file.type.startsWith('image/') || file.type.startsWith('video/')));

    useEffect(() => {
        if (allMediaToShow.length > 1) {
            setShowIntervalInput(true);
            const interval = setInterval(() => {
                setCurrentImageIndex(prev => (prev + 1) % allMediaToShow.length);
            }, slideInterval * 1000);
            return () => clearInterval(interval);
        } else {
            setShowIntervalInput(false);
            setCurrentImageIndex(0);
        }
    }, [allMediaToShow.length, slideInterval]);

    useEffect(() => {
        const resetTimeout = () => {
            // Очищаем предыдущий таймаут
            if (inactivityTimeoutRef.current) {
                clearTimeout(inactivityTimeoutRef.current);
            }

            // Устанавливаем новый таймаут
            inactivityTimeoutRef.current = setTimeout(() => {
                console.log('Inactivity timeout reached, closing fullscreen mode');
                setFullscreenMode(false);
                setFullscreenPosts([]);
            }, SEVEN_MINUTES);
        };

        const handleActivity = () => {
            resetTimeout();
        };

        // Добавляем обработчики событий на весь документ
        const activityEvents = ['mousemove', 'keydown', 'click', 'scroll', 'touchstart'];

        activityEvents.forEach(event => {
            document.addEventListener(event, handleActivity);
        });

        // Запускаем первый таймаут
        resetTimeout();

        // Функция очистки
        return () => {
            if (inactivityTimeoutRef.current) {
                clearTimeout(inactivityTimeoutRef.current);
            }

            activityEvents.forEach(event => {
                document.removeEventListener(event, handleActivity);
            });
        };
    }, [setFullscreenMode, setFullscreenPosts, SEVEN_MINUTES]);

    const currentMedia = allMediaToShow[currentImageIndex];

    // Get scale class based on current image scale
    const getScaleClass = (scale) => {
        if (scale === 0.05) return 'scale-5';
        if (scale === 0.1) return 'scale-10';
        if (scale === 0.2) return 'scale-20';
        if (scale === 0.4) return 'scale-40';
        if (scale === 0.6) return 'scale-60';
        if (scale === 0.8) return 'scale-80';
        if (scale === 1.0) return 'scale-100';
        return 'scale-default';
    };

    return (
        <div className='full_screeen_mode'>
            <div className='add_counts'>
                <CiCirclePlus className='add_url' />
                <div className='counts'>{fullscreenPosts.filter(post => post.text && post.text.trim()).length}</div>
            </div>
            <div className='screnn_message'>
                {postsToShow.map((post, index) => (
                    <div key={`${post.id}-${index}`} className='fullscreen_post'>
                        <div className='txt_message_fullscren'>{post.text}</div>
                    </div>
                ))}
            </div>

            {currentMedia && (
                <div className='fullscreen_image_container'>
                    {currentMedia.type.startsWith('image/') ? (
                        <img
                            src={currentMedia.url}
                            alt=""
                            className={getScaleClass(currentMedia.scale)}
                            style={{
                                transform: `scale(${currentMedia.scale})`,
                                maxWidth: '100%',
                                maxHeight: '100%'
                            }}
                        />
                    ) : currentMedia.type.startsWith('video/') ? (
                        <video
                            src={currentMedia.url}
                            controls
                            className={getScaleClass(currentMedia.scale)}
                            style={{
                                transform: `scale(${currentMedia.scale})`,
                                maxWidth: '100%',
                                maxHeight: '100%'
                            }}
                        />
                    ) : null}
                </div>
            )}
        </div>
    );
};

export default FullscreenMode;